import{_ as a,c as e,ag as t,o as i}from"./chunks/framework.mHuDn-wg.js";const r="/assets/2025-01-04-17-07-33.DP8FZRiA.png",_=JSON.parse('{"title":"基础知识","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/存储.md","filePath":"计算机/存储.md","lastUpdated":null}'),o={name:"计算机/存储.md"};function s(n,l,c,u,h,d){return i(),e("div",null,l[0]||(l[0]=[t('<h1 id="基础知识" tabindex="-1">基础知识 <a class="header-anchor" href="#基础知识" aria-label="Permalink to &quot;基础知识&quot;">​</a></h1><ul><li>硬盘的基本存储单位: <strong>扇区</strong>(sector), 一个 sector 一般 512 Byte(字节)~4096 Byte</li><li>现在市售的SSD硬盘, 扇区多为4KB</li><li>4K对齐是一种硬盘分区技术, 4K指的是物理扇区大小为4KB(4096Byte)的硬盘, 对齐时确保硬盘的逻辑分区与物理扇区对齐, 从而提高读写效率. <ul><li>现代操作系统在格式化硬盘时通常会默认进行4K对齐, 手动对齐需要专业的软件工具</li><li><img src="'+r+'" alt=""></li></ul></li><li><strong>簇</strong>(block)=几个连续的 sector, 常见有4KB, 8KB, 16KB</li><li>文件存储时占用的空间以簇为单位分配, 因此文件真实大小 &lt;= 文件占用空间</li><li>一些很小的文件不会&quot;占用空间&quot;, 是因为和文件元信息存储在了一起. <ul><li><a href="https://learn.microsoft.com/zh-cn/windows/win32/devnotes/master-file-table" target="_blank" rel="noreferrer">主文件表 (MFT)</a></li></ul></li><li>簇的使用提高了存储效率, 但簇越大存储空间的浪费越明显, 在格式化硬盘时可以选择簇, 一般保持默认即可</li></ul><h2 id="常见的文件系统" tabindex="-1">常见的文件系统 <a class="header-anchor" href="#常见的文件系统" aria-label="Permalink to &quot;常见的文件系统&quot;">​</a></h2><ul><li>磁盘的文件系统是操作系统用于管理存储设备上数据的一种机制, 是组织和存储文件的逻辑方式</li><li>将磁盘空间划分为多个逻辑区域，并通过目录结构组织这些区域中的文件和数据</li><li>允许用户以文件的形式存储和访问数据，而无需关心底层硬件的具体细节</li></ul><h3 id="btrfs" tabindex="-1">btrfs <a class="header-anchor" href="#btrfs" aria-label="Permalink to &quot;btrfs&quot;">​</a></h3><ul><li>Btrfs（B-Tree文件系统）是一种由Oracle公司于2007年开发的新型文件系统，旨在取代Linux上的ext3和ext4文件系统</li><li>在Linux系统中，可以通过安装<code>btrfs-progs</code>软件包来获取创建和管理Btrfs文件系统</li></ul><h3 id="ntfs" tabindex="-1">ntfs <a class="header-anchor" href="#ntfs" aria-label="Permalink to &quot;ntfs&quot;">​</a></h3><ul><li>NTFS（New Technology File System） ：Windows系统中广泛使用的文件系统，支持大容量存储和高级功能。</li></ul><h3 id="ext" tabindex="-1">ext <a class="header-anchor" href="#ext" aria-label="Permalink to &quot;ext&quot;">​</a></h3><ul><li>ext4：Linux系统中常用的文件系统，具有高性能和高可靠性。</li></ul><h3 id="fat" tabindex="-1">FAT <a class="header-anchor" href="#fat" aria-label="Permalink to &quot;FAT&quot;">​</a></h3><ul><li>FAT（File Allocation Table） ：早期的文件系统，适用于小容量存储设备。</li></ul><h3 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h3><ul><li>HFS+（Hierarchical File System Plus） ：苹果macOS系统中使用的文件系统。</li><li>XFS：高性能的日志型文件系统，适用于大规模数据存储</li></ul>',14)]))}const m=a(o,[["render",s]]);export{_ as __pageData,m as default};
